import java.io.*;

public class XSSVulnerableCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String name = reader.readLine();

        System.out.println("Hello, " + name + "!"); // This line is vulnerable to XSS

        // This line should properly handle user input to prevent XSS
        System.out.println("Hello, " + sanitizeInput(name) + "!");
    }

    private static String sanitizeInput(String input) {
        // Replace potentially harmful characters with harmless ones
        return input.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

